import json
import os

# Input priority: syslog_message > alerts > alert_file
alerts_input = []
input_mode   = 'unknown'
_syslog_msg  = None

syslog_msg = inputs.get('syslog_message') or inputs.get('syslog')
if syslog_msg and isinstance(syslog_msg, dict):
    raw_text = syslog_msg.get('message', '')
    if raw_text:
        try:
            alert = json.loads(raw_text)
            alert['_syslog_meta'] = {
                'hostname':  syslog_msg.get('hostname', ''),
                'app_name':  syslog_msg.get('app_name', ''),
                'timestamp': syslog_msg.get('timestamp', ''),
                'severity':  syslog_msg.get('severity'),
                'facility':  syslog_msg.get('facility'),
                'format':    syslog_msg.get('format', ''),
            }
            alerts_input = [alert]
            input_mode   = 'syslog'
            _syslog_msg  = syslog_msg
            print(f'[receive] syslog mode: host={syslog_msg.get("hostname")!r} '
                  f'app={syslog_msg.get("app_name")!r} '
                  f'severity={syslog_msg.get("severity")} '
                  f'format={syslog_msg.get("format")!r}')
        except (json.JSONDecodeError, TypeError) as _e:
            print(f'[receive] WARNING: syslog.message not valid JSON ({_e}), '
                  f'raw={raw_text[:120]!r}')
    else:
        print('[receive] WARNING: syslog_message.message is empty, skipping')

if not alerts_input:
    alerts_input = inputs.get('alerts', inputs.get('alert_list', []))
    if alerts_input:
        input_mode = 'alerts'

if not alerts_input:
    alert_file = inputs.get('alert_file', '')
    if alert_file:
        alert_file = os.path.expanduser(str(alert_file))
        try:
            with open(alert_file, 'r', encoding='utf-8') as _f:
                alerts_input = json.load(_f)
            input_mode = 'alert_file'
            print(f'[receive] file mode: loaded {len(alerts_input) if isinstance(alerts_input, list) else 1} alerts')
        except Exception as _e:
            print(f'[receive] WARNING: failed to load alert_file={alert_file!r}: {_e}')
            alerts_input = []

if isinstance(alerts_input, str):
    try:
        alerts_input = json.loads(alerts_input)
    except Exception:
        alerts_input = []
if isinstance(alerts_input, dict) and 'data' in alerts_input:
    alerts_input = alerts_input.get('data', [])
if not isinstance(alerts_input, list):
    alerts_input = [alerts_input] if alerts_input else []

if not alerts_input:
    print('[receive] WARNING: no alerts (syslog_message, alerts, alert_file all empty)')

# ── Source log type resolution ────────────────────────────────────────────────
def _detect_from_syslog_meta(sm):
    for field in ('app_name', 'hostname'):
        val = str(sm.get(field, '') or '').lower()
        if 'skyeye' in val:
            return 'skyeye', f'syslog.{field}={sm.get(field)!r}'
        if 'tdp' in val:
            return 'tdp', f'syslog.{field}={sm.get(field)!r}'
    return None, None

def _detect_from_alert_json(alert):
    if not isinstance(alert, dict):
        return None, None
    if isinstance(alert.get('net'), dict):
        return 'tdp', 'alert has nested net dict (TDP)'
    if any(k in alert for k in ('behave_uuid', 'flow_id')):
        return 'tdp', 'alert has behave_uuid/flow_id (TDP)'
    if any(k in alert for k in ('net_real_src_ip', 'net_http_url', 'threat_suuid')):
        return 'tdp', 'alert has pre-flattened TDP fields'
    if any(k in alert for k in ('uri', 'vuln_name', 'attack_result', 'attack_flag')):
        return 'skyeye', 'alert has uri/vuln_name/attack_result (Skyeye)'
    return None, None

explicit_type = str(inputs.get('source_log_type', '') or '').lower()
if explicit_type in ('tdp', 'skyeye'):
    source_log_type = explicit_type
    source_log_type_reason = 'explicit input parameter'
elif input_mode == 'syslog' and _syslog_msg:
    source_log_type, reason = _detect_from_syslog_meta(_syslog_msg)
    if source_log_type:
        source_log_type_reason = f'syslog metadata: {reason}'
    else:
        first_alert = alerts_input[0] if alerts_input else {}
        source_log_type, reason = _detect_from_alert_json(first_alert)
        if source_log_type:
            source_log_type_reason = f'JSON field detection: {reason}'
        else:
            source_log_type = 'tdp'
            source_log_type_reason = 'fallback default'
else:
    first_alert = alerts_input[0] if alerts_input else {}
    source_log_type, reason = _detect_from_alert_json(first_alert)
    if source_log_type:
        source_log_type_reason = f'JSON field detection: {reason}'
    else:
        source_log_type = 'tdp'
        source_log_type_reason = 'default'

print(f'[receive] source_log_type={source_log_type!r} reason={source_log_type_reason!r}')

filter_enabled  = bool(inputs.get('filter_enabled', True))
dedup_enabled   = bool(inputs.get('dedup_enabled', True))
threshold       = float(inputs.get('threshold', 0.7))
strict_fields   = inputs.get('strict_fields', ['sip', 'dip'])
lsh_fields      = inputs.get('lsh_fields', ['req_http_url', 'req_body', 'rsp_body'])
max_field_len   = int(inputs.get('max_field_len', 500))
max_dedup_keys  = int(inputs.get('max_dedup_keys', 100000))
if max_dedup_keys < 1:
    max_dedup_keys = 100000

print(f'[receive] input_mode={input_mode} raw_alerts={len(alerts_input)} '
      f'filter_enabled={filter_enabled} dedup_enabled={dedup_enabled} '
      f'max_dedup_keys={max_dedup_keys}')

outputs['raw_alerts']             = alerts_input
outputs['input_mode']             = input_mode
outputs['source_log_type']        = source_log_type
outputs['source_log_type_reason'] = source_log_type_reason
outputs['filter_enabled']         = filter_enabled
outputs['dedup_enabled']          = dedup_enabled
outputs['dedup_threshold']        = threshold
outputs['strict_fields']          = strict_fields
outputs['lsh_fields']             = lsh_fields
outputs['max_field_len']          = max_field_len
outputs['max_dedup_keys']         = max_dedup_keys
outputs['stats']                  = {'raw_count': len(alerts_input)}

normalized_alerts = inputs.get('normalized_alerts', [])
filter_enabled    = inputs.get('filter_enabled', True)
batch_hint        = str(inputs.get('source_log_type', 'tdp') or 'tdp').lower()
if batch_hint not in ('tdp', 'skyeye'):
    batch_hint = 'tdp'
stats = dict(inputs.get('stats', {}))

def is_scan_alert(threat_name):
    tnl = str(threat_name or '').lower()
    return ('扫描' in tnl) and ('webshell' not in tnl)

def get_threat_type(alert):
    src = alert.get('_source_type') or batch_hint
    if src == 'skyeye':
        return str(alert.get('threat_type', 'general') or 'general')
    return str(alert.get('threat_name', 'general') or 'general')

def is_http(alert):
    for field in ('application_layer_protocol', 'net_type', 'net_app_proto'):
        val = str(alert.get(field, '') or '').lower()
        if val and val != 'none' and 'http' in val:
            return True
    return False

def get_process_type(alert):
    src = alert.get('_source_type') or batch_hint
    threat_name = alert.get('threat_name', '')
    direction   = str(alert.get('direction', '') or '').lower()
    scan = is_scan_alert(threat_name)
    http = is_http(alert)
    if src == 'skyeye':
        return 'alert_scan_direction_in' if scan else 'alert_not_scan_http_direction_in'
    if scan:
        return f'alert_scan_direction_{direction}' if direction in ('in', 'out', 'lateral') else 'alert_scan_direction_in'
    if http:
        return f'alert_not_scan_http_direction_{direction}' if direction in ('in', 'out', 'lateral') else 'alert_not_scan_http_direction_in'
    return f'alert_not_scan_not_http_direction_{direction}' if direction in ('in', 'out', 'lateral') else 'alert_not_process'

NEED_ANALYSIS = {
    'alert_not_scan_http_direction_in',
    'alert_not_scan_http_direction_out',
    'alert_not_scan_http_direction_lateral',
}

filtered = []
process_type_counts = {}
for alert in normalized_alerts:
    alert = dict(alert)
    if filter_enabled:
        ptype       = get_process_type(alert)
        need        = ptype in NEED_ANALYSIS
        threat_type = get_threat_type(alert)
    else:
        ptype       = 'filter_disabled'
        need        = True
        threat_type = get_threat_type(alert)
    process_type_counts[ptype] = process_type_counts.get(ptype, 0) + 1
    alert['_process_type'] = ptype
    alert['_threat_type']  = threat_type
    if need:
        filtered.append(alert)

print(f'[filter] input={len(normalized_alerts)}, kept={len(filtered)}')
print(f'[filter] process_type_counts={process_type_counts}')

stats['after_filter_count']         = len(filtered)
stats['filter_removed_count']       = len(normalized_alerts) - len(filtered)
stats['filter_process_type_counts'] = process_type_counts

outputs['filtered_alerts'] = filtered
outputs['stats'] = stats
for k in ['input_mode', 'dedup_enabled', 'dedup_threshold', 'strict_fields',
          'lsh_fields', 'max_field_len', 'max_dedup_keys']:
    outputs[k] = inputs.get(k)
